const logicItem = $('Get NQ Logic Document').first().json;
const marketItem = $('Build NQ Input Pack').first().json;

let logicDocument = logicItem.content || '';

if (logicItem.encoding === 'base64') {
  logicDocument = Buffer.from(logicDocument, 'base64').toString('utf8');
}

return [
  {
    json: {
      logic_document: logicDocument,
      market_snapshot: marketItem
    }
  }
];

const openAiItem = $input.first().json;

let text =
  openAiItem.output?.[0]?.content?.[0]?.text ||
  openAiItem.text ||
  openAiItem.message ||
  '';

if (!text) {
  throw new Error('No OpenAI text output found');
}

const report = JSON.parse(text);

const marketSnapshot = $('Combine md & market snapshot').first().json.market_snapshot || {};

function pct(value) {
  if (value === null || value === undefined || value === '') return null;
  const match = String(value).match(/(\d+(\.\d+)?)/);
  return match ? Number(match[1]) : null;
}

function reasonFor(tf) {
  return (
    report[`${tf}_reason`] ||
    report.reasoning_summary ||
    ''
  );
}

return [
  {
    json: {
      snapshot_id: marketSnapshot.snapshot_id || null,
      agent_name: 'NQ',
      layer: 1,
      run_time_et: marketSnapshot.run_time_et || new Date().toISOString(),
      snapshot_date: marketSnapshot.snapshot_date || new Date().toISOString().slice(0, 10),
      market_inputs: marketSnapshot.available_inputs || {},


      call_24h_direction: report.direction_24h || null,
      call_24h_conviction: pct(report.conviction_24h),
      call_24h_reason: reasonFor('24h'),

      call_3d_direction: report.direction_3_day || null,
      call_3d_conviction: pct(report.conviction_3_day),
      call_3d_reason: reasonFor('3d'),

      call_current_week_direction: report.direction_current_week || null,
      call_current_week_conviction: pct(report.conviction_current_week),
      call_current_week_reason: reasonFor('current_week'),

      call_next_week_direction: report.direction_next_week || null,
      call_next_week_conviction: pct(report.conviction_next_week),
      call_next_week_reason: reasonFor('next_week'),

      call_current_month_direction: report.direction_current_month || null,
      call_current_month_conviction: pct(report.conviction_current_month),
      call_current_month_reason: reasonFor('current_month'),

      direction_24h: report.direction_24h || null,
      conviction_24h: pct(report.conviction_24h),
      direction_3_day: report.direction_3_day || null,
      conviction_3_day: pct(report.conviction_3_day),
      direction_current_week: report.direction_current_week || null,
      conviction_current_week: pct(report.conviction_current_week),
      direction_next_week: report.direction_next_week || null,
      conviction_next_week: pct(report.conviction_next_week),
      direction_current_month: report.direction_current_month || null,
      conviction_current_month: pct(report.conviction_current_month),

      factor_breakdown: report.factor_breakdown || {},
      conviction_model: report.conviction_model || {},
timeframe_models: report.timeframe_models || {},
weighted_score: report.weighted_score || null,
     warnings: report.risk_flags || report.warnings || [],
      full_output: report,
      raw_agent_output: report,

      logic_document: 'agent_nq_direction.md',
      logic_document_version: report.logic_document_version || '2.0_weighted_engine',
      bull_case: report.bull_case || null,
bear_case: report.bear_case || null,
winning_side: report.winning_side || null,

      score_bullish: report.score_bullish ?? null,
      score_bearish: report.score_bearish ?? null,
      score_neutral: report.score_neutral ?? null
    }
  }
];

const item = $input.first().json;
const inputs = item.market_inputs || {};

function n(v) {
  const x = Number(v);
  return Number.isFinite(x) ? x : null;
}

function makeFactor(signal, evidence, reason) {
  return { signal, evidence, reason };
}

function pctLabel(v) {
  const x = n(v);
  return x === null ? "missing" : `${Math.round(x * 100) / 100}`;
}

const TIMEFRAME_WEIGHTS = {
  "24h": {
    F1: 20, F2: 14, F3: 12, F4: 6, F5: 14,
    F6: 12, F7: 8, F8: 10, F9: 2, F10: 2
  },
  "3d": {
    F1: 18, F2: 14, F3: 12, F4: 7, F5: 16,
    F6: 14, F7: 7, F8: 7, F9: 3, F10: 2
  },
  "current_week": {
    F1: 16, F2: 12, F3: 12, F4: 8, F5: 18,
    F6: 16, F7: 6, F8: 6, F9: 4, F10: 2
  },
  "next_week": {
    F1: 14, F2: 8, F3: 12, F4: 8, F5: 20,
    F6: 20, F7: 5, F8: 5, F9: 5, F10: 3
  },
  "current_month": {
    F1: 12, F2: 6, F3: 12, F4: 8, F5: 22,
    F6: 20, F7: 5, F8: 6, F9: 5, F10: 4
  }
};

function chooseDelta(tf, d1, d5, d20) {
  if (tf === "24h" && n(d1) !== null) return d1;
  if ((tf === "next_week" || tf === "current_month") && n(d20) !== null) return d20;
  if (n(d5) !== null) return d5;
  if (n(d1) !== null) return d1;
  return null;
}

function latestEventSignal() {
  const ev = inputs.latest_us_event;
  const text = JSON.stringify(ev || {}).toLowerCase();

  if (!ev) {
    return makeFactor("NEUTRAL", "No recent US event", "No confirmed US economic surprise");
  }

  if (text.includes("bullish") || text.includes("positive") || text.includes("beat")) {
    return makeFactor("BULLISH", JSON.stringify(ev), "Positive US surprise supports NQ through growth/liquidity confidence");
  }

  if (text.includes("bearish") || text.includes("negative") || text.includes("miss")) {
    return makeFactor("BEARISH", JSON.stringify(ev), "Negative US surprise pressures NQ through growth risk");
  }

  return makeFactor("NEUTRAL", JSON.stringify(ev), "No clear NQ economic surprise signal");
}

function factorSignals(tf) {
  const vix = n(inputs.vix_level);
  const vixDelta = tf === "24h" && n(inputs.vix_d1) !== null ? inputs.vix_d1 : inputs.vix_d5;

  const dxyDelta = chooseDelta(tf, inputs.dxy_d1, inputs.dxy_d5, inputs.dxy_d20);
  const nominal10yDelta = chooseDelta(tf, null, inputs.us_10y_d5_bps, inputs.us_10y_d20_bps);
  const real10yDelta = chooseDelta(tf, null, inputs.us_10y_real_yield_d5_bps, inputs.us_10y_real_yield_d20_bps);

  const nqDelta = chooseDelta(tf, inputs.nq_d1_pct, inputs.nq_d5_pct, inputs.nq_d20_pct);
  const btcDelta = chooseDelta(tf, inputs.btc_d1_pct, inputs.btc_d5_pct, inputs.btc_d20_pct);
  const goldDelta = chooseDelta(tf, inputs.gold_d1_pct, inputs.gold_d5_pct, inputs.gold_d20_pct);

  const fed = String(inputs.fed_bias || "").toLowerCase();

  const signals = {};

  signals.F1 = (() => {
    if (vix === null) return makeFactor("NEUTRAL", "Missing VIX", "Missing input");

    if (vix > 30) {
      return makeFactor("BEARISH", `VIX ${vix}`, "Crisis volatility regime is strongly bearish NQ");
    }

    if (vix > 22) {
      return makeFactor("BEARISH", `VIX ${vix}`, "Risk-off volatility regime is bearish NQ");
    }

    if (vix < 16) {
      return makeFactor("BULLISH", `VIX ${vix}`, "Low-volatility risk-on regime supports NQ");
    }

    return makeFactor("NEUTRAL", `VIX ${vix}`, "Neutral VIX regime");
  })();

  signals.F2 = (() => {
    const d = n(vixDelta);
    if (d === null) return makeFactor("NEUTRAL", "Missing VIX delta", "Missing input");

    if (d >= 2) {
      return makeFactor("BEARISH", `VIX delta ${pctLabel(d)}`, "Rising volatility pressures NQ");
    }

    if (d <= -2) {
      return makeFactor("BULLISH", `VIX delta ${pctLabel(d)}`, "Falling volatility supports NQ");
    }

    return makeFactor("NEUTRAL", `VIX delta ${pctLabel(d)}`, "Volatility change below threshold");
  })();

  signals.F3 = (() => {
    const d = n(dxyDelta);
    if (d === null) return makeFactor("NEUTRAL", "Missing DXY delta", "Missing input");

    const upThreshold = tf === "24h" ? 0.15 : 0.3;
    const downThreshold = tf === "24h" ? -0.15 : -0.3;

    if (d >= upThreshold) {
      return makeFactor("BEARISH", `DXY delta ${pctLabel(d)}%`, "Rising USD tightens financial conditions and pressures NQ");
    }

    if (d <= downThreshold) {
      return makeFactor("BULLISH", `DXY delta ${pctLabel(d)}%`, "Falling USD eases financial conditions and supports NQ");
    }

    return makeFactor("NEUTRAL", `DXY delta ${pctLabel(d)}%`, "USD move below threshold");
  })();

  signals.F4 = (() => {
    const d = n(nominal10yDelta);
    if (d === null) return makeFactor("NEUTRAL", "Missing US 10Y nominal yield delta", "Missing input");

    if (d >= 5) {
      return makeFactor("BEARISH", `US 10Y nominal delta ${pctLabel(d)} bps`, "Rising nominal yields can pressure duration-sensitive NQ");
    }

    if (d <= -5) {
      return makeFactor("BULLISH", `US 10Y nominal delta ${pctLabel(d)} bps`, "Falling nominal yields support duration-sensitive NQ");
    }

    return makeFactor("NEUTRAL", `US 10Y nominal delta ${pctLabel(d)} bps`, "Nominal yield move below threshold");
  })();

  signals.F5 = (() => {
    const d = n(real10yDelta);
    if (d === null) return makeFactor("NEUTRAL", "Missing US 10Y real yield delta", "Missing input");

    if (d >= 5) {
      return makeFactor("BEARISH", `US 10Y real yield delta ${pctLabel(d)} bps`, "Rising real yields are bearish long-duration growth equities");
    }

    if (d <= -5) {
      return makeFactor("BULLISH", `US 10Y real yield delta ${pctLabel(d)} bps`, "Falling real yields support long-duration growth equities");
    }

    return makeFactor("NEUTRAL", `US 10Y real yield delta ${pctLabel(d)} bps`, "Real yield move below threshold");
  })();

  signals.F6 = (() => {
    if (!fed || fed === "unknown") return makeFactor("NEUTRAL", "Fed bias unknown", "Missing input");

    if (fed.includes("hawkish")) {
      return makeFactor("BEARISH", `Fed bias ${fed}`, "Hawkish Fed bias tightens liquidity and pressures NQ");
    }

    if (fed.includes("dovish")) {
      return makeFactor("BULLISH", `Fed bias ${fed}`, "Dovish Fed bias eases liquidity and supports NQ");
    }

    return makeFactor("NEUTRAL", `Fed bias ${fed}`, "No clear Fed liquidity impulse");
  })();

  signals.F7 = latestEventSignal();

  signals.F8 = (() => {
    const d = n(nqDelta);
    if (d === null) return makeFactor("NEUTRAL", "Missing NQ price delta", "Missing input");

    const upThreshold = tf === "24h" ? 0.25 : 0.75;
    const downThreshold = tf === "24h" ? -0.25 : -0.75;

    if (d >= upThreshold) {
      return makeFactor("BULLISH", `NQ delta ${pctLabel(d)}%`, "NQ own price action confirms bullish pressure");
    }

    if (d <= downThreshold) {
      return makeFactor("BEARISH", `NQ delta ${pctLabel(d)}%`, "NQ own price action confirms bearish pressure");
    }

    return makeFactor("NEUTRAL", `NQ delta ${pctLabel(d)}%`, "NQ price move below confirmation threshold");
  })();

  signals.F9 = (() => {
    const d = n(btcDelta);
    if (d === null) return makeFactor("NEUTRAL", "Missing BTC delta", "Missing input");

    const upThreshold = tf === "24h" ? 0.5 : 1.5;
    const downThreshold = tf === "24h" ? -0.5 : -1.5;

    if (d >= upThreshold) {
      return makeFactor("BULLISH", `BTC delta ${pctLabel(d)}%`, "BTC strength confirms high-beta risk appetite");
    }

    if (d <= downThreshold) {
      return makeFactor("BEARISH", `BTC delta ${pctLabel(d)}%`, "BTC weakness warns of high-beta risk pressure");
    }

    return makeFactor("NEUTRAL", `BTC delta ${pctLabel(d)}%`, "BTC move below confirmation threshold");
  })();

  signals.F10 = (() => {
    const d = n(goldDelta);
    if (d === null) return makeFactor("NEUTRAL", "Missing gold delta", "Missing input");

    const upThreshold = tf === "24h" ? 0.3 : 0.75;
    const downThreshold = tf === "24h" ? -0.3 : -0.75;

    if (d >= upThreshold && vix !== null && vix > 22) {
      return makeFactor("BEARISH", `Gold delta ${pctLabel(d)}%, VIX ${vix}`, "Gold strength during risk-off confirms defensive flows away from NQ");
    }

    if (d <= downThreshold && vix !== null && vix < 22) {
      return makeFactor("BULLISH", `Gold delta ${pctLabel(d)}%, VIX ${vix}`, "Gold weakness outside risk-off supports risk appetite");
    }

    return makeFactor("NEUTRAL", `Gold delta ${pctLabel(d)}%`, "Gold does not provide a clean defensive-flow signal");
  })();

  return signals;
}

function scoreTimeframe(tf) {
  const weights = TIMEFRAME_WEIGHTS[tf];
  const signals = factorSignals(tf);

  let bullish = 0;
  let bearish = 0;
  let neutral = 0;

  let bullishCount = 0;
  let bearishCount = 0;
  let neutralCount = 0;

  const factorBreakdown = {};

  for (const [id, sig] of Object.entries(signals)) {
    const weight = weights[id] || 0;

    factorBreakdown[id] = {
      ...sig,
      weight
    };

    if (sig.signal === "BULLISH") {
      bullish += weight;
      bullishCount++;
    } else if (sig.signal === "BEARISH") {
      bearish += weight;
      bearishCount++;
    } else {
      neutral += weight;
      neutralCount++;
    }
  }

  const active = bullish + bearish;
  const bullishArgument = active > 0 ? Math.round((bullish / active) * 100) : 0;
  const bearishArgument = active > 0 ? Math.round((bearish / active) * 100) : 0;
  const neutralPct = Math.round(neutral);
  const directionalParticipationPct = Math.round(active);
  const netEdge = bullishArgument - bearishArgument;

  const baseDirection =
    bullish > bearish
      ? "BULLISH"
      : bearish > bullish
        ? "BEARISH"
        : "NO_CLEAR_BIAS";

  const absEdge = Math.abs(netEdge);

  const direction =
    baseDirection === "NO_CLEAR_BIAS"
      ? "NO_CLEAR_BIAS"
      : absEdge < 20
        ? `${baseDirection}_LEAN`
        : baseDirection;

  const conviction =
    baseDirection === "BULLISH"
      ? bullishArgument
      : baseDirection === "BEARISH"
        ? bearishArgument
        : 0;

  const strength =
    absEdge >= 40 ? "VERY_STRONG" :
    absEdge >= 25 ? "STRONG" :
    absEdge >= 15 ? "MODERATE" :
    "WEAK";

  const reason = `${tf} NQ deterministic score: bull case ${bullishArgument}%, bear case ${bearishArgument}%, neutral/inactive ${neutralPct}%, directional participation ${directionalParticipationPct}%, net edge ${netEdge > 0 ? "+" : ""}${netEdge}.`;

  return {
    direction,
    conviction,
    reason,
    factor_breakdown: factorBreakdown,
    score_bullish: bullishCount,
    score_bearish: bearishCount,
    score_neutral: neutralCount,
    weighted_score: {
      bullish_weight: bullish,
      bearish_weight: bearish,
      neutral_weight: neutral,
      active_weight: active,
      weight_margin: Math.abs(bullish - bearish)
    },
    conviction_model: {
      bullish_argument_pct: bullishArgument,
      bearish_argument_pct: bearishArgument,
      neutral_evidence_pct: neutralPct,
      neutral_pct: neutralPct,
      directional_participation_pct: directionalParticipationPct,
      active_participation_pct: directionalParticipationPct,
      winning_side: baseDirection,
      net_edge_pct: netEdge,
      final_conviction: conviction,
      verdict_strength: strength,
      bull_case_weight: bullish,
      bear_case_weight: bearish,
      neutral_weight: neutral,
      final_conviction_logic: reason,

      weighted_edge: Math.abs(netEdge) / 100,
      raw_conviction: conviction,
      base_conviction: conviction,
      participation: directionalParticipationPct,
      participation_cap: directionalParticipationPct,
      conflict_penalty: 0,
      missing_input_penalty: 0,
      agreement_boost: 0
    }
  };
}

const r24h = scoreTimeframe("24h");
const r3d = scoreTimeframe("3d");
const rWeek = scoreTimeframe("current_week");
const rNextWeek = scoreTimeframe("next_week");
const rMonth = scoreTimeframe("current_month");

const output = {
  ...(item.full_output || {}),

  direction_24h: r24h.direction,
  conviction_24h: r24h.conviction,
  reason_24h: r24h.reason,

  direction_3_day: r3d.direction,
  conviction_3_day: r3d.conviction,
  reason_3_day: r3d.reason,

  direction_current_week: rWeek.direction,
  conviction_current_week: rWeek.conviction,
  reason_current_week: rWeek.reason,

  direction_next_week: rNextWeek.direction,
  conviction_next_week: rNextWeek.conviction,
  reason_next_week: rNextWeek.reason,

  direction_current_month: rMonth.direction,
  conviction_current_month: rMonth.conviction,
  reason_current_month: rMonth.reason,

  weighted_score: r24h.weighted_score,
  conviction_model: r24h.conviction_model,
  factor_breakdown: r24h.factor_breakdown,

  timeframe_models: {
    "24h": r24h,
    "3d": r3d,
    "current_week": rWeek,
    "next_week": rNextWeek,
    "current_month": rMonth
  },

  score_bullish: r24h.score_bullish,
  score_bearish: r24h.score_bearish,
  score_neutral: r24h.score_neutral,

  reasoning_summary: `NQ weighted verdicts calculated deterministically by timeframe. 24h ${r24h.direction} ${r24h.conviction}%, 3d ${r3d.direction} ${r3d.conviction}%, current week ${rWeek.direction} ${rWeek.conviction}%, next week ${rNextWeek.direction} ${rNextWeek.conviction}%, current month ${rMonth.direction} ${rMonth.conviction}%.`
};

const {
  market_inputs,
  bull_case,
  bear_case,
  winning_side,
  risk_flags,
  timeframe_models,
  ...safeItem
} = item;

return [{
  json: {
    ...safeItem,

    call_24h_direction: output.direction_24h,
    call_24h_conviction: output.conviction_24h,
    call_24h_reason: output.reason_24h,

    call_3d_direction: output.direction_3_day,
    call_3d_conviction: output.conviction_3_day,
    call_3d_reason: output.reason_3_day,

    call_current_week_direction: output.direction_current_week,
    call_current_week_conviction: output.conviction_current_week,
    call_current_week_reason: output.reason_current_week,

    call_next_week_direction: output.direction_next_week,
    call_next_week_conviction: output.conviction_next_week,
    call_next_week_reason: output.reason_next_week,

    call_current_month_direction: output.direction_current_month,
    call_current_month_conviction: output.conviction_current_month,
    call_current_month_reason: output.reason_current_month,

    direction_24h: output.direction_24h,
    conviction_24h: output.conviction_24h,

    direction_3_day: output.direction_3_day,
    conviction_3_day: output.conviction_3_day,

    direction_current_week: output.direction_current_week,
    conviction_current_week: output.conviction_current_week,

    direction_next_week: output.direction_next_week,
    conviction_next_week: output.conviction_next_week,

    direction_current_month: output.direction_current_month,
    conviction_current_month: output.conviction_current_month,

    weighted_score: output.weighted_score,
    conviction_model: output.conviction_model,

    factor_breakdown: output.factor_breakdown,

    full_output: output,
    raw_agent_output: output,

    reasoning_summary: output.reasoning_summary,
    score_bullish: output.score_bullish,
    score_bearish: output.score_bearish,
    score_neutral: output.score_neutral
  }
}];
